const input = $('Execute Workflow Trigger').item.json;
const agent = $('Buscar agente').item.json;
const channel = $('Buscar canal').item.json;

if (!agent?.id) throw new Error('Agente nao encontrado: ' + input.agentId);
if (!channel?.channel_id) throw new Error('Canal nao encontrado: ' + input.channelId);

const parse = (v) => (typeof v === 'string' ? JSON.parse(v) : v);

return [{
  json: {
    agentId: agent.id,
    agentName: agent.name,
    baseInstructions: agent.base_instructions,
    basePersonality: parse(agent.base_personality),
    channel: {
      channelId: channel.channel_id,
      enabled: channel.enabled,
      useSharedPersonality: channel.use_shared_personality,
      useSharedKnowledgeBase: channel.use_shared_knowledge_base,
      personality: channel.personality ? parse(channel.personality) : null,
      instructions: channel.instructions || '',
    },
  },
}];

const d = $input.first().json;
const channel = d.channel || {};
const basePersonality = d.basePersonality || {};
const personality = channel.useSharedPersonality ? basePersonality : (channel.personality || basePersonality);

const level = (n) => (n < 34 ? 'baixa' : n < 67 ? 'equilibrada' : 'alta');

let systemPrompt = (d.baseInstructions || '').trim();
if (channel.instructions?.trim()) {
  systemPrompt += '\n\nInstrucoes do canal:\n' + channel.instructions.trim();
}
systemPrompt += '\n\nDiretrizes de estilo:';
systemPrompt += '\n- Formalidade: ' + level(personality.formality ?? 50);
systemPrompt += '\n- Objetividade: ' + level(personality.objectivity ?? 50);
systemPrompt += '\n- Nivel tecnico: ' + level(personality.technicalLevel ?? 50);
systemPrompt += '\n- Estilo de escrita: ' + (personality.writingStyle || 'equilibrado');
systemPrompt += '\n- Emojis: ' + (personality.emojiUsage || 'as_vezes');
systemPrompt += '\n- Tamanho das respostas: ' + (personality.responseLength || 'media');

const kc = (d.knowledgeContext || '').trim();
if (kc) {
  systemPrompt += '\n\n## Base de conhecimento relevante\n' + kc;
  systemPrompt += '\n\nUse apenas as informacoes acima quando pertinentes. Se nao souber, diga que nao tem a informacao.';
}

const temperature = (personality.temperature ?? 50) / 100;
const max_tokens = { curta: 256, media: 512, longa: 1024 }[personality.responseLength] || 512;
const top_p = 0.5 + ((personality.creativity ?? 50) / 200);

return [{ json: { systemPrompt, personality, llmParams: { temperature, max_tokens, top_p } } }];

const input = $('Execute Workflow Trigger').item.json;
const embedding = $input.first().json.data[0].embedding;
const vectorLiteral = '[' + embedding.join(',') + ']';
const topK = input.topK || 5;

return [{ json: { ...input, vectorLiteral, topK } }];

const rows = $input.all().map(i => i.json);
const hits = rows.filter(r => r.content).map(r => ({
  content: r.content,
  score: Number(r.score),
  fileId: r.file_id,
  chunkIndex: r.chunk_index,
})).filter(h => h.score >= 0.7);

const knowledgeContext = hits.map(h => h.content).join('\n---\n');
return [{ json: { hits, knowledgeContext } }];

const item = $input.first().json;
const headers = item.headers || {};
const secret = headers['x-webhook-secret'] || headers['X-Webhook-Secret'];
const expected = $env.N8N_WEBHOOK_SECRET || 'dev-n8n-secret';
if (secret !== expected) return [{ json: { unauthorized: true } }];
const body = item.body ?? item;
return [{ json: { unauthorized: false, source: 'webhook', ...body } }];

const item = $input.first().json;
const viaWebhook = item.source === 'webhook';
const body = viaWebhook ? item : item;
const p = body.personality || {};
const messages = [{ role: 'system', content: body.systemPrompt || 'Voce e um assistente util.' }];

for (const msg of (body.history || [])) {
  messages.push({ role: msg.role, content: msg.content });
}
messages.push({ role: 'user', content: body.userMessage });

const temperature = (p.temperature ?? 50) / 100;
const max_tokens = { curta: 256, media: 512, longa: 1024 }[p.responseLength] || 512;

return [{ json: { viaWebhook, messages, temperature, max_tokens } }];

const prep = $('Preparar LLM').item.json;
let reply = 'Desculpe, nao consegui processar sua mensagem agora. Tente novamente.';
try {
  const choices = $input.first().json.choices;
  if (choices?.[0]?.message?.content) {
    reply = choices[0].message.content;
  }
} catch {}
return [{ json: { reply } }];

