const item = $input.first().json;
const headers = item.headers || {};
const secret = headers['x-webhook-secret'] || headers['X-Webhook-Secret'];
const expected = $env.N8N_WEBHOOK_SECRET || 'dev-n8n-secret';
if (secret !== expected) throw new Error('Unauthorized');

const body = item.body ?? item;
if (!body.fileId || !body.agentId || !body.storageUrl || !body.downloadUrl) {
  throw new Error('Payload invalido');
}
return [{ json: body }];

const meta = $('Validar e iniciar').item.json;
const downloadUrl = meta.downloadUrl;
if (!downloadUrl) throw new Error('downloadUrl ausente no payload');

const response = await fetch(downloadUrl);
if (!response.ok) throw new Error('Falha ao baixar arquivo do S3: ' + response.status);
const buf = Buffer.from(await response.arrayBuffer());

let text = '';
if (meta.fileType === 'csv') {
  text = buf.toString('utf-8');
} else if (meta.fileType === 'xlsx') {
  throw new Error('Processamento de XLSX ainda nao implementado no N8N. Use CSV por enquanto.');
} else {
  throw new Error('Tipo nao suportado: ' + meta.fileType + '. Use csv ou xlsx.');
}

const chunkSize = 3200;
const overlap = 320;
const chunks = [];
let i = 0;
let idx = 0;
while (i < text.length) {
  const slice = text.slice(i, i + chunkSize).trim();
  if (slice) chunks.push({ content: slice, chunkIndex: idx++ });
  if (i + chunkSize >= text.length) break;
  i += chunkSize - overlap;
}

if (!chunks.length) throw new Error('Nenhum texto extraido do arquivo');
return [{ json: { ...meta, chunks } }];

const meta = $('Extrair e chunkar').item.json;
const apiKey = $env.OPENAI_API_KEY;
if (!apiKey) throw new Error('OPENAI_API_KEY nao configurada');

const results = [];
for (const chunk of meta.chunks) {
  const res = await fetch('https://api.openai.com/v1/embeddings', {
    method: 'POST',
    headers: {
      Authorization: 'Bearer ' + apiKey,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ model: 'text-embedding-3-small', input: chunk.content }),
  });
  const data = await res.json();
  if (!data.data?.[0]?.embedding) throw new Error('Falha no embedding');
  results.push({
    content: chunk.content,
    chunkIndex: chunk.chunkIndex,
    embedding: data.data[0].embedding,
  });
}
return [{ json: { fileId: meta.fileId, chunks: results } }];

