const p = $input.first().json;
const instanceName = p.instance || p.instanceName || p.data?.instance;
const event = (p.event || p.data?.event || '').toLowerCase();

let connectionStatus = 'disconnected';
let qrCode = null;
let phoneNumber = null;
let connectedAt = null;

if (event.includes('qrcode')) {
  connectionStatus = 'connecting';
  qrCode = p.data?.qrcode?.base64 || p.qrcode || p.data?.qrcode || null;
} else if (event.includes('open') || p.data?.state === 'open') {
  connectionStatus = 'connected';
  phoneNumber = p.data?.phoneNumber || p.data?.wid?.user || null;
  connectedAt = new Date().toISOString();
} else if (event.includes('close')) {
  connectionStatus = 'disconnected';
} else if (event.includes('connecting')) {
  connectionStatus = 'reconnecting';
}

if (!instanceName || !String(instanceName).startsWith('flowassist-')) {
  return [{ json: { skip: true } }];
}

return [{ json: { skip: false, instanceName, connectionStatus, qrCode, phoneNumber, connectedAt } }];

const p = $input.first().json;
if (p.data?.key?.fromMe === true) return [{ json: { skip: true } }];

const instanceName = p.instance || p.instanceName;
const remoteJid = p.data?.key?.remoteJid || '';
const contactName = p.data?.pushName || 'Contato';
const msg = p.data?.message || {};
const message = msg.conversation || msg.extendedTextMessage?.text || '';

if (!message?.trim() || !instanceName) return [{ json: { skip: true } }];

const suffix = String(instanceName).replace('flowassist-', '');
return [{
  json: {
    skip: false,
    instanceName,
    agentIdSuffix: suffix,
    contactPhone: remoteJid,
    contactName,
    externalId: remoteJid,
    message: message.trim(),
  },
}];

const parse = $('Parse mensagem').item.json;
const row = $input.first().json;
if (!row.agent_id) throw new Error('Agente nao encontrado para ' + parse.instanceName);
return [{ json: { agentId: row.agent_id, channelId: 'whatsapp', ...parse } }];

const cfg = $input.first().json;
const parse = $('Prep agente').item.json;
return [{
  json: {
    agentId: cfg.agentId,
    query: parse.message,
    topK: 5,
    useSharedKnowledgeBase: cfg.channel.useSharedKnowledgeBase,
    cfg,
    parse,
  },
}];

const rag = $input.first().json;
const prep = $('Prep RAG').item.json;
return [{
  json: {
    agentName: prep.cfg.agentName,
    baseInstructions: prep.cfg.baseInstructions,
    basePersonality: prep.cfg.basePersonality,
    channel: prep.cfg.channel,
    knowledgeContext: rag.knowledgeContext || '',
    parse: prep.parse,
  },
}];

const prompt = $input.first().json;
const parse = $('Prep prompt').item.json.parse;
return [{
  json: {
    systemPrompt: prompt.systemPrompt,
    history: [],
    userMessage: parse.message,
    personality: prompt.personality,
    knowledgeContext: $('Prep prompt').item.json.knowledgeContext || '',
    parse,
  },
}];

